};

static inline float half_to_float(uint16_t h) {
  const uint16_t h_exp = (h & 0x7C00u);
  const uint16_t h_sig = (h & 0x03FFu);
  const uint32_t f_sgn = ((uint32_t)h & 0x8000u) << 16;
  uint32_t f_exp, f_sig;

  if (h_exp == 0x0000u) {
    if (h_sig == 0) {
      f_exp = 0;
      f_sig = 0;
    } else {
      int shift = 0;
      uint16_t sig = h_sig;
      while ((sig & 0x0400u) == 0) {
        sig <<= 1;
        ++shift;
      }
      sig &= 0x03FFu;
      f_exp = (uint32_t)(127 - 15 - shift) << 23;
      f_sig = (uint32_t)sig << 13;
    }
  } else if (h_exp == 0x7C00u) {
    f_exp = 0xFFu << 23;
    f_sig = (uint32_t)h_sig << 13;
  } else {
    f_exp = (uint32_t)(((h_exp >> 10) + (127 - 15)) & 0xFFu) << 23;
    f_sig = (uint32_t)h_sig << 13;
  }

  union {
    uint32_t u;
    float f;
  } v{f_sgn | f_exp | f_sig};
  return v.f;
}

static inline uint16_t float_to_half(float f) {
  union {
    float f;
    uint32_t u;
  } v{f};

  uint32_t sign = (v.u >> 16) & 0x8000u;
  uint32_t exp = (v.u >> 23) & 0xFFu;
  uint32_t mant = v.u & 0x7FFFFFu;

  if (exp == 0xFFu) {
    if (mant) return (uint16_t)(sign | 0x7E00u);
    return (uint16_t)(sign | 0x7C00u);
  }

  int32_t new_exp = (int32_t)exp - 127 + 15;
  if (new_exp >= 31) return (uint16_t)(sign | 0x7C00u);
  if (new_exp <= 0) {
    if (new_exp < -10) return (uint16_t)sign;
    mant |= 0x800000u;
    uint32_t sub = mant >> (1u - (uint32_t)new_exp + 13u);
    return (uint16_t)(sign | ((sub + 1) >> 1));
  }

  uint16_t h_exp = (uint16_t)new_exp << 10;
  uint16_t h_mant = (uint16_t)(mant >> 13);
  return (uint16_t)(sign | h_exp | h_mant);
}

template <typename T>
static inline T op_muladd(T a, T seed) {
  return a * a + seed;
}
template <>
inline int op_muladd<int>(int a, int seed) {
  long long t = (long long)a * (long long)a + (long long)seed;
  return (int)t;
}
template <>
inline cl_half2 op_muladd<cl_half2>(cl_half2 a, cl_half2 seed) {
  float ax = half_to_float(a.x), ay = half_to_float(a.y);
  float sx = half_to_float(seed.x), sy = half_to_float(seed.y);
  cl_half2 r;
  r.x = float_to_half(ax * ax + sx);
  r.y = float_to_half(ay * ay + sy);
  return r;
}

template <typename T>
static inline T op_mul(T a, T b) {
  return a * b;
}
template <>
inline int op_mul<int>(int a, int b) {
  long long t = (long long)a * (long long)b;
  return (int)t;
}
template <>
inline cl_half2 op_mul<cl_half2>(cl_half2 a, cl_half2 b) {
  float ax = half_to_float(a.x), ay = half_to_float(a.y);
  float bx = half_to_float(b.x), by = half_to_float(b.y);
  cl_half2 r;
  r.x = float_to_half(ax * bx);
  r.y = float_to_half(ay * by);
  return r;
}

template <typename T>
static inline T op_add(T a, T b) {
  return a + b;
}
template <>
inline int op_add<int>(int a, int b) {
  long long t = (long long)a + (long long)b;
  return (int)t;
}
template <>
inline cl_half2 op_add<cl_half2>(cl_half2 a, cl_half2 b) {
  float ax = half_to_float(a.x), ay = half_to_float(a.y);
  float bx = half_to_float(b.x), by = half_to_float(b.y);
  cl_half2 r;
  r.x = float_to_half(ax + bx);
  r.y = float_to_half(ay + by);
  return r;
}

template <typename T>
static inline bool is_equal(T a, T b) {
  return a == b;
}
template <>
inline bool is_equal<cl_half2>(cl_half2 a, cl_half2 b) {
  return a.x == b.x && a.y == b.y;
}

template <typename T>
void benchmark_func_cpu(T seed,
                        T* g_data,
                        long size,
                        bool block_strided,
                        size_t workgroupsize,
                        unsigned int elements_per_wi,
                        unsigned int fusion_degree,
                        int compute_iters) {
  const long compute_grid_size = size / (long)elements_per_wi / (long)fusion_degree;
  if (compute_grid_size <= 0) return;
  const long blockSize = (long)workgroupsize;
  long num_groups = blockSize > 0 ? (compute_grid_size / blockSize) : 1;
  if (num_groups <= 0) num_groups = 1;
  const long grid_size = blockSize * num_groups;
  const long big_stride = num_groups * blockSize * (long)elements_per_wi;

#pragma omp parallel for schedule(static)
  for (long gid = 0; gid < compute_grid_size; gid++) {
    const long group_id = blockSize ? (gid / blockSize) : 0;
    const long local_id = blockSize ? (gid % blockSize) : gid;
    const long stride = block_strided ? blockSize : grid_size;
    const long idx =
        block_strided ? (group_id * blockSize * (long)elements_per_wi + local_id) : gid;

    std::vector<T> tmps(elements_per_wi);
    for (unsigned int k = 0; k < fusion_degree; k++) {
      for (unsigned int j = 0; j < elements_per_wi; j++) {
        long index = idx + (long)j * stride + (long)k * big_stride;
        if (index < 0) continue;
        index %= size;
        tmps[j] = g_data[index];
        for (int i = 0; i < compute_iters; i++) tmps[j] = op_muladd<T>(tmps[j], seed);
      }

      T sum{};
      for (unsigned int j = 0; j + 1 < elements_per_wi; j += 2)
        sum = op_add<T>(sum, op_mul<T>(tmps[j], tmps[j + 1]));

      T minus_one{};
      if constexpr (std::is_same<T, cl_half2>::value) {
        minus_one = cl_half2{0xBC00u, 0xBC00u};
      } else {
        minus_one = (T)-1;
      }

      if (is_equal<T>(sum, minus_one)) {
        long out_idx = idx + (long)k * big_stride;
        if (out_idx >= 0) {
          out_idx %= size;
          g_data[out_idx] = sum;
        }
      }
    }
  }
}

template <int N, typename F>
double benchmark(F&& func) {
  double best = std::numeric_limits<double>::infinity();
  for (int i = 0; i < N; i++) {
    double t = func();
    if (t < best) best = t;
  }
  return best;
}

void flushed_printf(const char* format, ...) {
  va_list args;
  va_start(args, format);
  vprintf(format, args);
  va_end(args);
  fflush(stdout);
}

void show_progress_init(int length) {
  flushed_printf("[");
  for (int i = 0; i < length; i++) flushed_printf(" ");
  flushed_printf("]");
  for (int i = 0; i <= length; i++) flushed_printf("\b");
}
void show_progress_step(int domove, char newchar) {
  flushed_printf("%c", newchar);
  if (!domove) flushed_printf("\b");
}
void show_progress_done(void) { flushed_printf("\n"); }

